    private void validateResponseElement(Element responseElement) {
        if (responseElement == null) {
            throw new SamlProcessingException("Missing Response element");
        }
        String localName = responseElement.getLocalName();
        String namespaceUri = responseElement.getNamespaceURI();
        if (!"Response".equals(localName) || !SAML_NS.equals(namespaceUri)) {
            throw new SamlProcessingException("Invalid SAML Response element");
        }

        String id = responseElement.getAttribute("ID");
        if (id == null || id.trim().isEmpty()) {
            throw new SamlProcessingException("SAML Response missing ID");
        }

        String version = responseElement.getAttribute("Version");
        if (!"2.0".equals(version)) {
            throw new SamlProcessingException("Unsupported SAML version");
        }

        String issueInstant = responseElement.getAttribute("IssueInstant");
        if (issueInstant == null || issueInstant.trim().isEmpty()) {
            throw new SamlProcessingException("SAML Response missing IssueInstant");
        }
        try {
            Instant.parse(issueInstant);
        } catch (Exception e) {
            throw new SamlProcessingException("Invalid IssueInstant format");
        }
    }

    private List<Element> findAssertions(Document doc) throws Exception {
        XPath xpath = XPathFactory.newInstance().newXPath();
        xpath.setNamespaceContext(new SimpleNamespaceContext());
        NodeList nodes = (NodeList) xpath.evaluate("//saml:Assertion", doc, XPathConstants.NODESET);
        if (nodes == null) {
            return Collections.emptyList();
        }
        List<Element> assertions = new ArrayList<>();
        for (int i = 0; i < nodes.getLength(); i++) {
            Node node = nodes.item(i);
            if (node instanceof Element) {
                assertions.add((Element) node);
            }
        }
        return assertions;
    }

    private void validateAssertion(Element assertion) {
        if (assertion == null) {
            throw new SamlProcessingException("Invalid Assertion element");
        }
        if (!"Assertion".equals(assertion.getLocalName()) || !ASSERTION_NS.equals(assertion.getNamespaceURI())) {
            throw new SamlProcessingException("Invalid Assertion namespace");
        }

        String id = assertion.getAttribute("ID");
        if (id == null || id.trim().isEmpty()) {
            throw new SamlProcessingException("Assertion missing ID");
        }

        String issueInstant = assertion.getAttribute("IssueInstant");
        if (issueInstant == null || issueInstant.trim().isEmpty()) {
            throw new SamlProcessingException("Assertion missing IssueInstant");
        }
        try {
            Instant.parse(issueInstant);
        } catch (Exception e) {
            throw new SamlProcessingException("Invalid Assertion IssueInstant");
        }

        Element subject = firstChildElementByLocalName(assertion, "Subject");
        if (subject == null) {
            throw new SamlProcessingException("Assertion missing Subject");
        }
    }

    private String extractNameId(Element assertion) {
        Element subject = firstChildElementByLocalName(assertion, "Subject");
        if (subject == null) {
            return null;
        }
        Element nameId = firstChildElementByLocalName(subject, "NameID");
        return nameId != null ? textContent(nameId) : null;
    }

    private Map<String, List<String>> extractAttributes(Element assertion) {
        Map<String, List<String>> attributes = new LinkedHashMap<>();
        Element attrStatement = firstChildElementByLocalName(assertion, "AttributeStatement");
        if (attrStatement == null) {
            return attributes;
        }

        NodeList children = attrStatement.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node node = children.item(i);
            if (!(node instanceof Element)) {
                continue;
            }
            Element attribute = (Element) node;
            if (!"Attribute".equals(attribute.getLocalName()) || !ASSERTION_NS.equals(attribute.getNamespaceURI())) {
                continue;
            }
            String attrName = attribute.getAttribute("Name");
            if (attrName == null || attrName.trim().isEmpty()) {
                continue;
            }
            List<String> values = attributes.computeIfAbsent(attrName, k -> new ArrayList<>());
            NodeList valueNodes = attribute.getChildNodes();
            for (int j = 0; j < valueNodes.getLength(); j++) {
                Node valueNode = valueNodes.item(j);
                if (valueNode instanceof Element) {
                    Element valueElement = (Element) valueNode;
                    if ("AttributeValue".equals(valueElement.getLocalName()) && ASSERTION_NS.equals(valueElement.getNamespaceURI())) {
                        String value = textContent(valueElement);
                        if (value != null) {
                            values.add(value);
                        }
                    }
                }
            }
        }
        return attributes;
    }

    private boolean isAuthenticated(Element responseElement, Element assertion) {
        Element status = firstChildElementByLocalName(responseElement, "Status");
        if (status != null) {
            Element statusCode = firstChildElementByLocalName(status, "StatusCode");
            if (statusCode != null) {
                String value = statusCode.getAttribute("Value");
                if (value != null && !value.contains("Success")) {
                    return false;
                }
            }
        }

        Element subjectConfirmation = firstChildElementByLocalName(assertion, "SubjectConfirmation");
        if (subjectConfirmation != null) {
            Element subjectConfirmationData = firstChildElementByLocalName(subjectConfirmation, "SubjectConfirmationData");
            if (subjectConfirmationData != null) {
                String notOnOrAfter = subjectConfirmationData.getAttribute("NotOnOrAfter");
                if (notOnOrAfter != null && !notOnOrAfter.trim().isEmpty()) {
                    try {
                        if (Instant.now().isAfter(Instant.parse(notOnOrAfter))) {
                            return false;
                        }
                    } catch (Exception e) {
                        return false;
                    }
                }
            }
        }

        Element conditions = firstChildElementByLocalName(assertion, "Conditions");
        if (conditions != null) {
            String notBefore = conditions.getAttribute("NotBefore");
            String notOnOrAfter = conditions.getAttribute("NotOnOrAfter");
            try {
                Instant now = Instant.now();
                if (notBefore != null && !notBefore.trim().isEmpty() && now.isBefore(Instant.parse(notBefore))) {
                    return false;
                }
                if (notOnOrAfter != null && !notOnOrAfter.trim().isEmpty() && !now.isBefore(Instant.parse(notOnOrAfter))) {
                    return false;
                }
            } catch (Exception e) {
                return false;
            }
        }

        return true;
    }

    private String createSessionId(String nameId, Map<String, List<String>> attributes) {
        SecureRandom random = new SecureRandom();
        UUID uuid = new UUID(random.nextLong(), random.nextLong());
        String principal = nameId != null ? nameId : "anonymous";
        int hash = principal.hashCode();
        if (attributes != null) {
            hash = 31 * hash + attributes.hashCode();
        }
        return uuid.toString() + "-" + Integer.toHexString(hash) + "-" + Instant.now().toEpochMilli();
    }

    private Element firstChildElementByLocalName(Element parent, String localName) {
        if (parent == null) {
            return null;
        }
        NodeList nodes = parent.getChildNodes();
        for (int i = 0; i < nodes.getLength(); i++) {
            Node node = nodes.item(i);
            if (node instanceof Element) {
                Element element = (Element) node;
                if (localName.equals(element.getLocalName())) {
                    return element;
                }
            }
        }
        return null;
    }

    private String textContent(Element element) {
        if (element == null) {
            return null;
        }
        String value = element.getTextContent();
        return value != null ? value.trim() : null;
    }

    private String docToString(Document doc) throws Exception {
        TransformerFactory tf = TransformerFactory.newInstance();
        tf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        Transformer transformer = tf.newTransformer();
        transformer.setOutputProperty(OutputKeys.OMIT_XML_DECLARATION, "yes");
        transformer.setOutputProperty(OutputKeys.INDENT, "no");
        StringWriter writer = new StringWriter();
        transformer.transform(new DOMSource(doc), new StreamResult(writer));
        return writer.toString();
    }
